// Evaluate idle signal + pending work + kill-switch.
// Respects:
//   - idle threshold: 10 min (no titan-authored decisions in last 10 min)
//   - pending work: at least one operator_task_queue row pending + pre_approved
//   - kill-switch: skip if tla-nudge-disabled OR tla-disabled decision exists
//   - dedupe: skip if same (idle-trigger-ts, queue-snapshot-hash) fired in last 15 min (unless urgent)
//   - grace window: 5 min post any Path 1/2/3 restart invocation
//   - urgent override: always fire for tasks with priority=urgent
const latestTitan = $input.first().json[0] || {};
const pending = $('Pending pre-approved tasks').first().json || [];
const killswitch = $('Kill-switch check (tla-nudge-disabled or tla-disabled)').first().json || [];

const now = Date.now();
const latestTitanTs = latestTitan.created_at ? new Date(latestTitan.created_at).getTime() : 0;
const idleMinutes = latestTitanTs === 0 ? 9999 : (now - latestTitanTs) / 60000;
const IDLE_THRESHOLD_MIN = 10;
const urgent = pending.some(t => (t.priority || '').toLowerCase() === 'urgent');
const killed = Array.isArray(killswitch) && killswitch.length > 0;

if (killed) {
  return [{ json: { should_fire: false, reason: 'kill_switch_active', idle_minutes: idleMinutes } }];
}
if (pending.length === 0) {
  return [{ json: { should_fire: false, reason: 'queue_empty', idle_minutes: idleMinutes } }];
}
if (idleMinutes < IDLE_THRESHOLD_MIN && !urgent) {
  return [{ json: { should_fire: false, reason: 'not_idle_yet', idle_minutes: idleMinutes, pending_count: pending.length } }];
}

const queueHash = pending.map(t => t.task_id).sort().join(',');
const fireTs = Math.floor(now / 1000);
const phrase = '«MCP_QUEUE_POLL» poll MCP queue for pending tasks tagged today';
return [{ json: { should_fire: true, ts: fireTs, phrase, queue_hash: queueHash, urgent, pending_count: pending.length, idle_minutes: idleMinutes } }];

// Build HMAC-signed POST body.
// Canonical string: "<ts>\n<body>"
// Header: X-Titan-Sig = hex-encoded HMAC-SHA256(secret, canonical)
const crypto = require('crypto');
const incoming = $input.first().json;
const secret = $env.TLA_NUDGE_HMAC_SECRET;
if (!secret) throw new Error('TLA_NUDGE_HMAC_SECRET env var missing');
const body = JSON.stringify({ phrase: incoming.phrase, urgent: !!incoming.urgent });
const canonical = `${incoming.ts}\n${body}`;
const sig = crypto.createHmac('sha256', secret).update(canonical).digest('hex');
return [{ json: { body, sig, ts: incoming.ts, queue_hash: incoming.queue_hash, urgent: incoming.urgent, pending_count: incoming.pending_count, idle_minutes: incoming.idle_minutes } }];
